1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteInput {
13	  customer: Customer;
14	  items: Item[];
15	}
16	
17	const PROCESSING_FEE = 5;
18	const BLOCK_SIZE = 3;
19	const RUNE_BLOCK_PREMIUM = 60;
20	const FIRST_INSURANCE_RATE = 0.1;
21	const LOYALTY_RATE = 0.2;
22	const LOYALTY_MIN_YEARS = 2;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	};
31	
32	const unitPriceFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
33	
34	const isRune = (item: Item): boolean => item.type === "rune";
35	
36	const isMainItem = (item: Item): boolean => !isRune(item);
37	
38	const runeBasePremium = (runeCount: number): number =>
39	  runeCount === BLOCK_SIZE
40	    ? RUNE_BLOCK_PREMIUM
41	    : runeCount * unitPriceFor("rune");
42	
43	const sumUnitPrices = (items: Item[]): number =>
44	  items.reduce((sum, item) => sum + unitPriceFor(item.type), 0);
45	
46	const countRunes = (items: Item[]): number => items.filter(isRune).length;
47	
48	const totalBasePremium = (items: Item[]): number =>
49	  sumUnitPrices(items.filter(isMainItem)) + runeBasePremium(countRunes(items));
50	
51	const itemBasePremium = (item: Item): number =>
52	  isRune(item) ? unitPriceFor("rune") : unitPriceFor(item.type);
53	
54	const itemSurcharges = (item: Item): number =>
55	  item.cursed ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
56	
57	const totalSurcharges = (items: Item[]): number =>
58	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
59	
60	const firstInsuranceSurcharge = (policyBase: number): number =>
61	  policyBase * FIRST_INSURANCE_RATE;
62	
63	const isLoyal = (customer: Customer): boolean =>
64	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
65	
66	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
67	  isLoyal(customer) ? policyBase * LOYALTY_RATE : 0;
68	
69	export const quote = (input: QuoteInput): number => {
70	  const policyBase = totalBasePremium(input.items);
71	  const premiumBeforeFee =
72	    policyBase +
73	    totalSurcharges(input.items) +
74	    firstInsuranceSurcharge(policyBase) -
75	    loyaltyDiscount(policyBase, input.customer);
76	  return Math.ceil(premiumBeforeFee + PROCESSING_FEE);
77	};
78	
79	export const claim = (...args: unknown[]): unknown => {
80	  return undefined;
81	};
82

1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Quote: base premiums for single main items ---
6	  it("quote: empty item list → premium 5 G (only the processing fee)", () => {
7	    expect(quote({ customer: { yearsWithMHPCO: 0 }, items: [] })).toBe(5);
8	  });
9	  it("quote: single sword (steel, ench 3), 0 yrs first quote → premium 115 G (100 base + 10 first insurance + 5 fee)", () => {
10	    expect(
11	      quote({
12	        customer: { yearsWithMHPCO: 0 },
13	        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
14	      })
15	    ).toBe(115);
16	  });
17	  it("quote: single amulet, 0 yrs first quote → premium 71 G (60 base + 6 first insurance + 5 fee)", () => {
18	    expect(
19	      quote({ customer: { yearsWithMHPCO: 0 }, items: [{ type: "amulet" }] })
20	    ).toBe(71);
21	  });
22	  it("quote: single staff, 0 yrs first quote → premium 93 G (80 base + 8 first insurance + 5 fee)", () => {
23	    expect(
24	      quote({ customer: { yearsWithMHPCO: 0 }, items: [{ type: "staff" }] })
25	    ).toBe(93);
26	  });
27	  it("quote: single potion, 0 yrs first quote → premium 49 G (40 base + 4 first insurance + 5 fee)", () => {
28	    expect(
29	      quote({ customer: { yearsWithMHPCO: 0 }, items: [{ type: "potion" }] })
30	    ).toBe(49);
31	  });
32	
33	  // --- Quote: components and building blocks (base premiums; first insurance applies to policy base) ---
34	  it("quote: 2 runes, 0 yrs first quote → base 50 G → premium 60 G (50 + 5 first insurance + 5 fee)", () => {
35	    expect(
36	      quote({
37	        customer: { yearsWithMHPCO: 0 },
38	        items: [{ type: "rune" }, { type: "rune" }],
39	      })
40	    ).toBe(60);
41	  });
42	  it("quote: 3 runes, 0 yrs first quote → base 60 G (block applies) → premium 71 G (60 + 6 first insurance + 5 fee)", () => {
43	    expect(
44	      quote({
45	        customer: { yearsWithMHPCO: 0 },
46	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
47	      })
48	    ).toBe(71);
49	  });
50	  it("quote: 4 runes, 0 yrs first quote → base 100 G (no block, exactly 3 required) → premium 115 G (100 + 10 first insurance + 5 fee)", () => {
51	    expect(
52	      quote({
53	        customer: { yearsWithMHPCO: 0 },
54	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
55	      })
56	    ).toBe(115);
57	  });
58	  it.todo("quote: 7 runes → base 175 G (no block, 7≠3, 7×25) → premium 198 G (175 + 17.5 first insurance + 5 fee, rounded up)");
59	  it.todo("quote: 2 runes + 1 moonstone → base 75 G (no block, different types) → premium 80 G");
60	  it.todo("quote: 3 runes + 3 moonstones → base 120 G (two separate blocks) → premium 125 G");
61	
62	  // --- Quote: item-specific modifiers ---
63	  it("quote: cursed sword (ench 3), 0 yrs first quote → base 100 + 50 curse + 10 first insurance + 5 fee = 165 G", () => {
64	    expect(
65	      quote({
66	        customer: { yearsWithMHPCO: 0 },
67	        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
68	      })
69	    ).toBe(165);
70	  });
71	  it.todo("quote: sword with exactly enchantment 5 → +30% high-enchantment surcharge (100 + 30 = 130) → premium 135 G");
72	  it.todo("quote: sword with enchantment 4 → no high-enchantment surcharge → premium 105 G");
73	  it.todo("quote: cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 = 180) → premium 185 G");
74	
75	  // --- Quote: policy-wide modifiers ---
76	  it("quote: loyalty discount applies at exactly 2 years (-20% of policy base) → premium 95 G (100 + 10 first - 20 loyalty + 5 fee)", () => {
77	    expect(
78	      quote({
79	        customer: { yearsWithMHPCO: 2 },
80	        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
81	      })
82	    ).toBe(95);
83	  });
84	  it.todo("quote: first insurance surcharge (+10%) applies to a first contract");
85	  it.todo("quote: follow-up contract discount (-15%) applies to the second quote in a scenario");
86	
87	  // --- Quote: modifier scope on multi-item policies ---
88	  it.todo("quote: cursed sword (100) + plain amulet (60) → base 160; curse adds 50 (50% of sword) → 210 before further modifiers and fee");
89	
90	  // --- Quote: rounding ---
91	  it.todo("quote: premium of 197.5 G rounds UP to 198 G (MHPCO's favor)");
92	
93	  // --- Quote: integration examples ---
94	  it.todo("quote integration: newcomer (0 yrs, first contract) cursed sword (steel, ench 3) → 165 G (100 + 50 curse + 10 first + 5 fee)");
95	  it.todo("quote integration: long-standing (3 yrs), 2nd quote, cursed sword (steel, ench 7) → 160 G (100 + 50 + 30 - 20 loyalty + 10 first - 15 follow-up + 5 fee)");
96	
97	  // --- Claim: standard reimbursement ---
98	  it.todo("claim: regular sword (steel, ench 3), damage 500 → payout 400 G (full minus 100 deductible)");
99	  it.todo("claim: rune (value 250), damage 200 → payout 100 G (full minus 100 deductible, no special clause)");
100	
101	  // --- Claim: special clauses ---
102	  it.todo("claim: high-enchantment (≥8) sword, ench 8, dragon material, damage 1000 → payout 400 G (50% rule, then deductible)");
103	  it.todo("claim: dragon-material sword, ench 9, damage 1000 → payout 400 G (both clauses, 50% wins, then deductible)");
104	  it.todo("claim: dragon-material sword, ench 5, damage 800 → payout 700 G (dragon full reimbursement, then deductible)");
105	  it.todo("claim: steel sword, ench 9, damage 1000 → payout 400 G (high-enchantment 50% first, then deductible)");
106	
107	  // --- Claim: deductible per damage event ---
108	  it.todo("claim: dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");
109	
110	  // --- Claim: cap and insurance sum ---
111	  it.todo("claim: sword + amulet → insurance sum 1600, cap 3200");
112	  it.todo("claim: two swords → insurance sum 2000, cap 4000; two damage entries each own deductible");
113	  it.todo("claim: cursed sword → cap 2000 based on unmodified insurance value (modifiers do not raise cap)");
114	  it.todo("claim: sword + 3 runes (block) → insurance sum 1750 (block discount affects premium only, not insurance sum)");
115	
116	  // --- Claim: cap exhaustion across successive claims ---
117	  it.todo("claim: sword (cap 2000), first claim 1500 → payout 1400, remaining cap 600");
118	  it.todo("claim: sword (cap 2000), second claim 1500 → payout 600 (reduced to remaining cap), remaining cap 0");
119	
120	  // --- Claim: rounding ---
121	  it.todo("claim: payout of 350.5 G rounds DOWN to 350 G (MHPCO's favor)");
122	
123	  // --- Error / edge cases ---
124	  it.todo("error: quote includes an unknown item type (e.g. broomstick) → throws / rejected");
125	  it.todo("error: claim references a damage item not in the policy (e.g. amulet when only sword insured) → rejected");
126	  it.todo("error: claim has more damage entries of a type than the policy covers (two sword damages, one sword insured) → rejected");
127	  it.todo("error: claim has a damage entry with negative amount (-200) → rejected");
128	});
